const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const secret = body.internal_secret || '';
const expected = process.env.INTERNAL_EMAIL_SECRET || '';
if (!expected || secret !== expected) return { json: { _unauthorized: true, error: 'internal secret required' } };
if (!body.client_id || !Array.isArray(body.disclosure_types) || body.disclosure_types.length === 0) return { json: { _empty: true, error: 'client_id and disclosure_types[] required' } };
const valid = ['casl_consent','pipeda_privacy','conflict_of_interest','replacement_form','general'];
const types = body.disclosure_types.filter(function (t) { return valid.indexOf(t) >= 0; });
if (types.length === 0) return { json: { _empty: true, error: 'no valid disclosure types in input' } };
return { json: {
  _authorized: true,
  client_id: body.client_id,
  advisor_id: body.advisor_id || null,
  variables: body.variables || {},
  disclosure_types: types
} };

// Fan out one item per disclosure_type. Each downstream iteration will
// load the template (committed alongside this workflow), substitute
// variables, upload to R2, and insert a compliance_disclosures row.
const ctx = $json;
return ctx.disclosure_types.map(function (t) {
  return { json: {
    disclosure_type: t,
    template_id: t.replace(/_/g, '-'),  // file name pattern: documents/templates/insurance/<template_id>.html
    client_id: ctx.client_id,
    advisor_id: ctx.advisor_id,
    variables: ctx.variables
  } };
});

// MVP: inline template bodies. Phase 5b polish — read from R2 instead
// (reduces n8n bundle size + allows non-engineer compliance officer to
// edit templates without redeploy). Templates committed to repo at
// documents/templates/insurance/<template_id>.html for source-of-truth
// and version control; the inline copies here mirror their structure
// and will be regenerated from those files in a follow-up sync workflow.
const ctx = $json;
const tpl = ctx.template_id;
const v = ctx.variables || {};

const escapeHtml = function (s) { return String(s == null ? '' : s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'); };

const inlineTemplates = {
  'casl-consent':         '<!doctype html><html><head><meta charset="utf-8"><title>CASL Consent</title></head><body><h1>Express Consent — Canadian Anti-Spam Legislation (CASL)</h1><p>I, {{client_name}}, expressly consent to receive commercial electronic messages from {{advisor_company}} (via {{advisor_name}}) regarding insurance products, market intelligence, and related services. I understand I can withdraw consent at any time by replying STOP or emailing {{support_email}}.</p><p>Date: {{date}}</p><p>Signature: ________________________</p></body></html>',
  'pipeda-privacy':       '<!doctype html><html><head><meta charset="utf-8"><title>PIPEDA Privacy Notice</title></head><body><h1>Privacy Notice — PIPEDA Compliance</h1><p>{{advisor_company}} collects personal information from {{client_name}} for the purposes of: assessing insurance suitability, completing applications with carriers, fulfilling regulatory KYC/AML requirements, and ongoing service. Information is shared with carriers ONLY for application processing. You may access or correct your information by contacting {{support_email}}.</p><p>Date: {{date}}</p></body></html>',
  'conflict-of-interest': '<!doctype html><html><head><meta charset="utf-8"><title>Conflict of Interest Disclosure</title></head><body><h1>Advisor Compensation Disclosure</h1><p>{{advisor_name}} is compensated by carriers via commissions on policies sold. Commission structures vary by carrier and product. Specific commission disclosure: {{commission_disclosure}}. Conflicts (if any): {{conflicts_array}}. {{advisor_name}} is required by FSRA to recommend products in your best interest regardless of commission differentials.</p><p>Acknowledged by: {{client_name}}</p><p>Date: {{date}}</p></body></html>',
  'replacement-form':     '<!doctype html><html><head><meta charset="utf-8"><title>Life Insurance Replacement Disclosure</title></head><body><h1>Replacement Disclosure (Life Insurance)</h1><p>You are replacing existing coverage. Existing policy: {{existing_policy_details}}. New policy proposed: {{new_policy_details}}.</p><p>Comparison: {{comparison_table}}</p><p>You should NOT cancel existing coverage until new coverage is issued and in force. Acknowledged by {{client_name}} on {{date}}.</p></body></html>',
  'needs-analysis-record':'<!doctype html><html><head><meta charset="utf-8"><title>Suitability Record</title></head><body><h1>Suitability Documentation</h1><h2>Client Situation</h2><pre>{{client_situation}}</pre><h2>Needs Analysis</h2><pre>{{needs_analysis}}</pre><h2>Recommendations</h2><pre>{{recommendations}}</pre><h2>Advisor Reasoning</h2><p>{{advisor_reasoning}}</p></body></html>',
  'application-summary':  '<!doctype html><html><head><meta charset="utf-8"><title>Application Summary</title></head><body><h1>Application Summary for Review</h1><h2>Application Data</h2><pre>{{application_data}}</pre><h2>Premium</h2><p>{{premium_summary}}</p><h2>Coverage</h2><p>{{coverage_summary}}</p></body></html>',
  'coverage-comparison':  '<!doctype html><html><head><meta charset="utf-8"><title>Coverage Comparison</title></head><body><h1>Side-by-Side Comparison</h1><pre>{{products_array}}</pre><h2>Your Needs</h2><pre>{{client_needs}}</pre></body></html>'
};

let html = inlineTemplates[tpl];
if (!html) return { json: { _missing_template: true, template_id: tpl } };

// Substitute {{variables}}. Unknown vars stay as empty string.
html = html.replace(/\{\{(\w+)\}\}/g, function (_, name) {
  return escapeHtml(v[name] != null ? v[name] : '');
});

const storageKey = 'disclosures/insurance/' + ctx.client_id + '/' + tpl + '-' + Date.now() + '.html';

return { json: {
  storage_key: storageKey,
  html_body: html,
  template_id: tpl,
  client_id: ctx.client_id,
  advisor_id: ctx.advisor_id,
  disclosure_type: ctx.disclosure_type
} };
